126	/**
127	 * Recursively auto-close done children when a parent is closed.
128	 * Appends system-authored events to each child's issue file and updates the index.
129	 * Returns the updated index.
130	 */
131	async function cascadeClose(
132	  index: IndexFile,
133	  issueId: IssueId,
134	  trackerDir: string,
135	): Promise<IndexFile> {
136	  const childIds = getChildren(index, issueId);
137	  let currentIndex = index;
138	
139	  for (const childId of childIds) {
140	    const childEntry = findEntry(currentIndex, childId);
141	    if (!childEntry || childEntry.status !== "done") continue;
142	
143	    const now = new Date().toISOString();
144	    const event: Event = {
145	      type: "update",
146	      timestamp: now,
147	      author: "system",
148	      content: {
149	        status: "closed",
150	        reason: "auto-closed: parent closed",
151	      },
152	    };
153	
154	    const childPath = join(trackerDir, childEntry.path);
155	    await appendEvent(childPath, event);
156	
157	    currentIndex = updateEntry(currentIndex, childId, { status: "closed" });
158	
159	    // Recursively cascade to the child's own children
160	    currentIndex = await cascadeClose(currentIndex, childId, trackerDir);
161	  }
162	
163	  return currentIndex;
164	}
