166	/**
167	 * Tracker — the main programmatic API for trackgentic.
168	 *
169	 * Provides methods for issue CRUD, comments, blockages, user management,
170	 * and event history. The constructor accepts a `cwd` parameter that defaults
171	 * to `process.cwd()`. It does NOT validate that `.trackgentic/` exists at
172	 * construction time — resolution happens on each method call.
173	 *
174	 * @example
175	 * ```typescript
176	 * import { Tracker } from "trackgentic";
177	 *
178	 * const tracker = new Tracker("/path/to/project");
179	 * await tracker.init();
180	 * const { id } = await tracker.create({ title: "My first issue" });
181	 * ```
182	 */
183	export class Tracker {
184	  private cwd: string;
185	
186	  /**
187	   * Create a new Tracker instance.
188	   *
189	   * @param cwd - Working directory to resolve `.trackgentic/` from. Defaults to `process.cwd()`.
190	   */
191	  constructor(cwd?: string) {
192	    this.cwd = cwd ?? process.cwd();
193	  }
194	
195	  /**
196	   * Initialize a new `.trackgentic/` directory in `cwd`.
197	   *
198	   * Creates the directory structure with all initial files:
199	   * `config.json`, `index.json`, `dependencies.json`, `users.json`,
200	   * and an empty `issues/` subdirectory.
201	   *
202	   * @returns `{ result: "OK", path }` on success, or `{ result: "ALREADY_INITIALIZED", path }` if already exists
203	   *
204	   * @example
205	   * ```typescript
206	   * const result = await tracker.init();
207	   * if (result.result === "OK") console.log("Created at", result.path);
208	   * ```
209	   */
210	  async init(): Promise<InitResult> {
211	    const trackerDir = join(this.cwd, TRACKGENTIC_DIR);
212	
213	    if (existsSync(trackerDir)) {
214	      return { result: "ALREADY_INITIALIZED", path: resolve(trackerDir) };
215	    }
216	
217	    mkdirSync(trackerDir, { recursive: true });
218	    mkdirSync(join(trackerDir, "issues"), { recursive: true });
219	
220	    await atomicWriteJSON(join(trackerDir, "config.json"), DEFAULT_CONFIG);
221	    await atomicWriteJSON(join(trackerDir, "index.json"), DEFAULT_INDEX);
222	    await atomicWriteJSON(join(trackerDir, "dependencies.json"), DEFAULT_DEPENDENCIES);
223	    await atomicWriteJSON(join(trackerDir, "users.json"), DEFAULT_USERS);
224	
225	    return { result: "OK", path: resolve(trackerDir) };
226	  }
