231	   * Generates a unique ID, creates the issue file with creation + update events,
232	   * and inserts an entry into the sorted index. Validates parent constraints if
233	   * `parentId` is provided.
234	   *
235	   * @param params - Creation parameters
236	   * @param params.title - The issue title (required)
237	   * @param params.description - Optional description, defaults to ""
238	   * @param params.status - Initial status, defaults to "idea"
239	   * @param params.priority - Priority 1-5, defaults to 3
240	   * @param params.assignee - Optional assignee, defaults to null
241	   * @param params.tags - Optional tags, defaults to []
242	   * @param params.parentId - Optional parent issue ID for hierarchy
243	   * @param params.author - Override author (resolved by auth layer if not provided)
244	   * @returns `{ id }` on success, or a TrackgenticError on auth failure
245	   * @throws {TrackgenticError} NOT_INITIALIZED if no `.trackgentic/` directory
246	   * @throws {TrackgenticError} NOT_FOUND if parentId doesn't exist in index
247	   * @throws {TrackgenticError} HIERARCHY_CONSTRAINT if parent is closed
248	   *
249	   * @example
250	   * ```typescript
251	   * const { id } = await tracker.create({
252	   *   title: "Bug fix",
253	   *   priority: 1,
254	   *   tags: ["bug", "urgent"],
255	   * });
256	   * ```
257	   */
258	  async create(params: CreateParams): Promise<CreateResult> {
259	    const trackerDir = resolveTrackerDir(this.cwd);
260	    if (!trackerDir) {
261	      throw new TrackgenticError(
262	        ErrorCodes.NOT_INITIALIZED.result,
263	        "No .trackgentic/ directory found. Run `trackgentic init` first.",
264	        ErrorCodes.NOT_INITIALIZED.exitCode,
265	      );
266	    }
267	
268	    const config = await readJSON<ConfigFile>(join(trackerDir, "config.json"));
269	    const users = await readJSON<UsersFile>(join(trackerDir, "users.json"));
270	    const authResult = resolveAuthor({ config, users, requiresWrite: true });
271	    if (authResult instanceof TrackgenticError) return authResult;
272	    const author = params.author ?? authResult.author;
273	
274	    const id = generateId();
275	    const issuePath = params.path ?? `issues/${id}.json`;
276	    const now = new Date().toISOString();
277	
278	    const title = params.title;
279	    const description = params.description ?? "";
280	    const status: IssueStatus = params.status ?? "idea";
281	    const priority = params.priority ?? 3;
282	    const assignee = params.assignee ?? null;
283	    const parentId = params.parentId ?? null;
284	    const tags = params.tags ?? [];
285	
286	    // Read index early for parent validation
287	    const index = await readIndex(trackerDir);
288	
289	    // Validate parent exists and is not closed
290	    if (parentId) {
291	      const parentEntry = findEntry(index, parentId);
292	      if (!parentEntry) {
293	        throw new TrackgenticError(
294	          ErrorCodes.NOT_FOUND.result,
295	          `Parent issue \`${parentId}\` not found in index.`,
296	          ErrorCodes.NOT_FOUND.exitCode,
297	        );
298	      }
299	      const validationError = validateNewChild(parentEntry);
300	      if (validationError) {
301	        throw new TrackgenticError(
302	          ErrorCodes.HIERARCHY_CONSTRAINT.result,
303	          validationError,
304	          ErrorCodes.HIERARCHY_CONSTRAINT.exitCode,
305	        );
306	      }
307	    }
308	
309	    // Build update content with only non-default values
310	    const updateContent: Partial<
311	      Pick<
312	        IssueProperties,
313	        "title" | "description" | "status" | "assignee" | "tags" | "priority" | "parentId"
314	      >
315	    > & { title: string } = { title };
316	    if (description) updateContent.description = description;
317	    if (status !== "idea") updateContent.status = status;
318	    if (priority !== 3) updateContent.priority = priority;
319	    if (assignee !== null) updateContent.assignee = assignee;
320	    if (parentId !== null) updateContent.parentId = parentId;
321	    if (tags.length > 0) updateContent.tags = tags;
322	
323	    // Create issue file with two events: creation + update
324	    const creationEvent = { type: "creation" as const, timestamp: now, author };
325	    const updateEvent = {
326	      type: "update" as const,
327	      timestamp: now,
328	      author,
329	      content: updateContent,
330	    };
331	
332	    const issueFilePath = join(trackerDir, issuePath);
333	    await atomicWriteJSON(issueFilePath, [creationEvent, updateEvent]);
334	
335	    // Build index entry and insert into index
336	    const entry: IndexEntry = {
337	      id,
338	      title,
339	      path: issuePath,
340	      status,
341	      assignee,
342	      parentId,
343	      tags,
344	      priority,
345	    };
346	
