508	  /**
509	   * Get the recommended next issue to work on for a given user.
510	   *
511	   * Filters open issues by assignee and active status, excludes blocked issues,
512	   * then sorts by priority ASC → impact DESC → id ASC and returns the top issue.
513	   *
514	   * @param assignee - The assignee name to filter by (case-sensitive)
515	   * @returns The recommended ComputedIssue, or `{ result: "NO_ISSUES_AVAILABLE" }`
516	   * @throws {TrackgenticError} NOT_INITIALIZED if no `.trackgentic/` directory
517	   * @throws {TrackgenticError} TOKEN_REQUIRED if auth mode is strict and no token provided
518	   *
519	   * @example
520	   * ```typescript
521	   * const result = await tracker.next("alice");
522	   * if ("title" in result) console.log("Work on:", result.title);
523	   * else console.log("No issues available:", result.message);
524	   * ```
525	   */
526	  async next(assignee: string): Promise<NextResult> {
527	    const trackerDir = resolveTrackerDir(this.cwd);
528	    if (!trackerDir) {
529	      throw new TrackgenticError(
530	        ErrorCodes.NOT_INITIALIZED.result,
531	        "No .trackgentic/ directory found. Run `trackgentic init` first.",
532	        ErrorCodes.NOT_INITIALIZED.exitCode,
533	      );
534	    }
535	
536	    const config = await readJSON<ConfigFile>(join(trackerDir, "config.json"));
537	    const users = await readJSON<UsersFile>(join(trackerDir, "users.json"));
538	    const authResult = resolveAuthor({ config, users, requiresWrite: false });
539	    if (authResult instanceof TrackgenticError) {
540	      throw authResult;
541	    }
542	
543	    const index = await readIndex(trackerDir);
544	
545	    // Filter to open issues assigned to this user with actionable statuses
546	    const openStatuses: IssueStatus[] = ["idea", "todo", "in-progress"];
547	    let candidates = index.open.filter(
548	      (e) => e.assignee === assignee && openStatuses.includes(e.status),
549	    );
550	
551	    // Read dependencies for blockage filtering and impact scoring
552	    const deps = readDependenciesSync(trackerDir);
553	
554	    // Filter out issues with any active blockages
555	    candidates = candidates.filter((e) => {
556	      const blockedBy = deps.blockedBy[e.id] ?? [];
557	      return !blockedBy.some((b) => b.status === "active");
558	    });
559	
560	    // If no candidates remain, return no issues available
561	    if (candidates.length === 0) {
562	      return {
563	        result: "NO_ISSUES_AVAILABLE",
564	        message: `No unblocked issues found for user '${assignee}'.`,
565	      };
566	    }
567	
568	    // Sort: priority ASC → impact DESC → id ASC
569	    candidates.sort((a, b) => {
570	      if (a.priority !== b.priority) return a.priority - b.priority;
571	      const impactA = getImpactScore(deps, a.id);
572	      const impactB = getImpactScore(deps, b.id);
573	      if (impactA !== impactB) return impactB - impactA;
574	      return a.id.localeCompare(b.id);
575	    });
576	
577	    // Take top issue, replay events, return computed state
578	    const topEntry = candidates[0]!;
579	    const issueFilePath = join(trackerDir, topEntry.path);
580	    if (!existsSync(issueFilePath)) {
581	      throw new TrackgenticError(
582	        ErrorCodes.ISSUE_MISSING.result,
583	        `Issue file for \`${topEntry.id}\` is missing.`,
584	        ErrorCodes.ISSUE_MISSING.exitCode,
585	      );
586	    }
587	
588	    const events = await replayEvents(issueFilePath);
589	    return computeState(events, topEntry.id);
590	  }
