721	    // ── Build and append update event ──────────────────────────────
722	
723	    // Build update event content with only the provided fields
724	    const content: Partial<
725	      Pick<
726	        IssueProperties,
727	        "title" | "description" | "status" | "assignee" | "tags" | "priority" | "parentId"
728	      >
729	    > = {};
730	    if (params.title !== undefined) content.title = params.title;
731	    if (params.description !== undefined) content.description = params.description;
732	    if (params.status !== undefined) content.status = params.status;
733	    if (params.assignee !== undefined) content.assignee = params.assignee;
734	    if (params.tags !== undefined) content.tags = params.tags;
735	    if (params.priority !== undefined) content.priority = params.priority;
736	    if (params.parentId !== undefined) content.parentId = params.parentId;
