738	    const now = new Date().toISOString();
739	
740	    const updateEvent = {
741	      type: "update" as const,
742	      timestamp: now,
743	      author,
744	      content,
745	    };
746	
747	    // Append event to issue file
748	    await appendEvent(issueFilePath, updateEvent);
749	
750	    // Recompute state from all events
751	    const events = await replayEvents(issueFilePath);
752	    const computed = computeState(events, id);
753	
754	    // Update index entry with new computed values
755	    let updatedIndex = updateEntry(index, id, {
756	      title: computed.title,
757	      status: computed.status,
758	      assignee: computed.assignee,
759	      parentId: computed.parentId,
760	      tags: computed.tags,
761	      priority: computed.priority,
762	    });
763	
764	    // ── Hierarchy handling (after event append, before index write) ─
765	
766	    // 1. Handle reparenting (childrenOf updates)
767	    if (params.parentId !== undefined && params.parentId !== oldParentId) {
768	      // Detach from old parent
769	      if (oldParentId !== null) {
770	        updatedIndex = removeChild(updatedIndex, oldParentId, id);
771	      }
772	      // Attach to new parent
773	      if (params.parentId !== null) {
774	        updatedIndex = addChild(updatedIndex, params.parentId, id);
775	
776	        // Upward promotion for reparenting: if child's status is past new parent's status
777	        const newParentEntry = findEntry(updatedIndex, params.parentId);
778	        if (newParentEntry && isStatusAfter(computed.status, newParentEntry.status)) {
779	          const promotions = computeUpwardPromotions(
780	            updatedIndex,
781	            newParentEntry,
782	            computed.status,
783	            (iid) => findEntry(updatedIndex, iid),
784	          );
785	          for (const promo of promotions) {
786	            const promoEntry = findEntry(updatedIndex, promo.issueId);
787	            if (promoEntry && promo.event.type === "update" && promo.event.content.status) {
788	              await appendEvent(join(trackerDir, promoEntry.path), promo.event);
789	              updatedIndex = updateEntry(updatedIndex, promo.issueId, {
790	                status: promo.event.content.status,
791	              });
792	            }
793	          }
794	        }
795	      }
796	    }
