1221	   *
1222	   * Batch atomic: if adding any blocker would create a cycle, the entire batch
1223	   * is rejected and no changes are written. Validates that both the blocked issue
1224	   * and all blocker issues exist in the index.
1225	   *
1226	   * @param blockedId - The issue that is blocked
1227	   * @param params - Blockage parameters
1228	   * @param params.blockerIds - Array of blocker issue IDs
1229	   * @param params.author - Override author (resolved by auth layer if not provided)
1230	   * @returns `{ result: "OK" }` on success, or a TrackgenticError
1231	   * @throws {TrackgenticError} NOT_INITIALIZED if no `.trackgentic/` directory
1232	   * @throws {TrackgenticError} NOT_FOUND if blockedId or any blockerId is not in the index
1233	   * @throws {TrackgenticError} BLOCKAGE_CYCLE if adding the blockage would create a cycle
1234	   *
1235	   * @example
1236	   * ```typescript
1237	   * await tracker.blockagesAdd("blocked001", {
1238	   *   blockerIds: ["blocker001", "blocker002"],
1239	   * });
1240	   * ```
1241	   */
1242	  async blockagesAdd(blockedId: IssueId, params: BlockagesAddParams): Promise<BlockagesAddResult> {
1243	    const trackerDir = resolveTrackerDir(this.cwd);
1244	    if (!trackerDir) {
1245	      throw new TrackgenticError(
1246	        ErrorCodes.NOT_INITIALIZED.result,
1247	        "No .trackgentic/ directory found. Run `trackgentic init` first.",
1248	        ErrorCodes.NOT_INITIALIZED.exitCode,
1249	      );
1250	    }
1251	
1252	    const config = await readJSON<ConfigFile>(join(trackerDir, "config.json"));
1253	    const users = await readJSON<UsersFile>(join(trackerDir, "users.json"));
1254	    const authResult = resolveAuthor({ config, users, requiresWrite: true });
1255	    if (authResult instanceof TrackgenticError) return authResult;
1256	    const author = params.author ?? authResult.author;
1257	
1258	    const index = await readIndex(trackerDir);
1259	
1260	    // Validate blockedId exists
1261	    if (!findEntry(index, blockedId)) {
1262	      throw new TrackgenticError(
1263	        ErrorCodes.NOT_FOUND.result,
1264	        `Issue \`${blockedId}\` not found in index.`,
1265	        ErrorCodes.NOT_FOUND.exitCode,
1266	      );
1267	    }
1268	
1269	    // Validate all blockerIds exist
1270	    for (const blockerId of params.blockerIds) {
1271	      if (!findEntry(index, blockerId)) {
1272	        throw new TrackgenticError(
1273	          ErrorCodes.NOT_FOUND.result,
1274	          `Issue \`${blockerId}\` not found in index.`,
1275	          ErrorCodes.NOT_FOUND.exitCode,
1276	        );
1277	      }
1278	    }
1279	
1280	    const deps = await readDependencies(trackerDir);
1281	
1282	    // Projected state: deep clone and validate cycle for each blocker
1283	    let projected = {
1284	      blockedBy: { ...deps.blockedBy },
1285	      blocks: { ...deps.blocks },
1286	    };
1287	
1288	    for (const blockerId of params.blockerIds) {
1289	      projected = addBlockage(projected, blockedId, blockerId);
1290	      if (detectCycle(projected, blockedId, blockerId)) {
1291	        throw new TrackgenticError(
1292	          ErrorCodes.BLOCKAGE_CYCLE.result,
1293	          `Blockage would create a cycle: \`${blockedId}\` → ... → \`${blockerId}\`.`,
1294	          ErrorCodes.BLOCKAGE_CYCLE.exitCode,
1295	        );
1296	      }
1297	    }
1298	
1299	    // All passed — write projected state
1300	    await writeDependencies(trackerDir, projected);
1301	
1302	    // Append events to blockedId's issue file
1303	    const blockedEntry = findEntry(index, blockedId)!;
1304	    const issueFilePath = join(trackerDir, blockedEntry.path);
1305	
1306	    for (const blockerId of params.blockerIds) {
1307	      const now = new Date().toISOString();
1308	      const event: Event = {
1309	        type: "blockage-added",
1310	        timestamp: now,
1311	        author,
1312	        content: { blockerId },
1313	      };
1314	      await appendEvent(issueFilePath, event);
1315	    }
1316	
1317	    return { result: "OK" };
1318	  }
1319	
1320	  /**
