1366	    }
1367	
1368	    let deps = await readDependencies(trackerDir);
1369	
1370	    for (const blockerId of params.blockerIds) {
1371	      deps = resolveBlockage(deps, blockedId, blockerId);
1372	    }
1373	
1374	    await writeDependencies(trackerDir, deps);
1375	
1376	    // Append events
1377	    const blockedEntry = findEntry(index, blockedId)!;
1378	    const issueFilePath = join(trackerDir, blockedEntry.path);
1379	
