1427	    const config = await readJSON<ConfigFile>(join(trackerDir, "config.json"));
1428	    const users = await readJSON<UsersFile>(join(trackerDir, "users.json"));
1429	    const authResult = resolveAuthor({ config, users, requiresWrite: true });
